export interface Task {
  id: string;
  title: string;
  description: string;
  completed: boolean;
  userId: string;
  createdAt: string;
  updatedAt: string;
}

export const tasks: Map<string, Task> = new Map();

export function createTask(data: Omit<Task, 'id' | 'createdAt' | 'updatedAt'>): Task {
  const task: Task = { ...data, id: Math.random().toString(36).slice(2), createdAt: new Date().toISOString(), updatedAt: new Date().toISOString() };
  tasks.set(task.id, task);
  return task;
}

import { Router } from 'express';
import { requireAuth, AuthRequest } from '../middleware/auth';
import { createTask, getTask, updateTask, deleteTask, tasks } from '../models/task';

const router = Router();

router.get('/', requireAuth, (req: AuthRequest, res) => {
  const userTasks = [...tasks.values()].filter(t => t.userId === req.userId);
  res.json(userTasks);
});

router.post('/', requireAuth, (req: AuthRequest, res) => {
  const { title, description } = req.body;
  if (!title) { res.status(400).json({ error: 'title is required' }); return; }
  const task = createTask({ title, description: description ?? '', completed: false, userId: req.userId! });
  res.status(201).json(task);
});
